import { useState, useEffect } from 'react';
import { contentService } from '../../services/cmsService';

const defaultFaqs = [
  { question: 'L\'assurance decennale est-elle obligatoire pour un electricien ?', answer: 'Oui, l\'assurance decennale est obligatoire pour tout electricien qui realise des travaux de construction selon la loi Spinetta (1978). Sans cette assurance, vous ne pouvez pas exercer legalement et risquez des sanctions penales en cas de sinistre.' },
  { question: 'Quel est le prix moyen d\'une assurance decennale pour electricien ?', answer: 'Le prix varie selon votre statut : auto-entrepreneur (600-900€/an), artisan (1000-2000€/an), societe (sur devis). Le tarif depend aussi de votre chiffre d\'affaires, votre experience et les garanties souhaitees.' },
  { question: 'Que se passe-t-il apres 8 ans ?', answer: 'Apres 8 ans, la garantie decennale prend fin pour les travaux nouveaux. Cependant, les dommages reveles avant la fin de la 10eme annee sont toujours couverts. Passe ce delai, seul subsiste la garantie RC Pro pour les dommages en cours.' },
  { question: 'Quelle est la difference entre RC Pro et decennale ?', answer: 'La RC Pro (Responsabilite Civile Professionnelle) couvre les dommages causes pendant les travaux. La garantie decennale couvre les defauts de construction qui apparaissent apres reception des travaux pendant 10 ans.' },
  { question: 'Un auto-entrepreneur doit-il avoir une assurance decennale ?', answer: 'Oui, meme en statut auto-entrepreneur, l\'assurance decennale est obligatoire si vous realizez des travaux de construction. Cela inclut les travaux electriques neufs, renovation et installation.' },
  { question: 'Que couvre l\'assurance decennale pour electricien ?', answer: 'Elle couvert les dommages lies a votre intervention electrique : defect d\'installation, probleme de cablage, tableau electrique defectueux, court-circuit, incendie d\'origine electrique, et dommages aux tiers.' }
];

export default function FAQ() {
  const [faqs, setFaqs] = useState(defaultFaqs);
  const [openIndex, setOpenIndex] = useState(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const data = await contentService.getFaqs();
        if (data && data.length > 0) {
          setFaqs(data.map(f => ({
            question: f.question,
            answer: f.answer
          })));
        }
      } catch (e) {
        console.log('Using default FAQ data');
      }
    };
    fetchData();
  }, []);

  return (
    <section id="faq" className="py-12 md:py-20 bg-gray-50">
      <div className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center mb-10 md:mb-14">
          <h2 className="text-2xl sm:text-3xl md:text-4xl font-bold text-gray-900">
            Questions <span className="text-yellow-600">frequentes</span>
          </h2>
          <p className="mt-3 sm:mt-4 text-gray-600 text-base md:text-lg">
            Tout ce que vous devez savoir sur l'assurance decennale pour electricien
          </p>
        </div>

        <div className="space-y-3 sm:space-y-4">
          {faqs.map((faq, index) => (
            <div key={index} className="bg-white rounded-xl shadow-sm overflow-hidden">
              <button
                className="w-full px-4 sm:px-6 py-4 sm:py-5 text-left flex items-center justify-between"
                onClick={() => setOpenIndex(openIndex === index ? null : index)}
              >
                <span className="font-semibold text-gray-900 pr-3 sm:pr-4 text-sm sm:text-base">{faq.question}</span>
                <span className={`text-lg sm:text-2xl text-yellow-600 transition-transform flex-shrink-0 ml-2 ${openIndex === index ? 'rotate-180' : ''}`}>
                  ▼
                </span>
              </button>
              {openIndex === index && (
                <div className="px-4 sm:px-6 pb-4 sm:pb-5 text-gray-600 text-sm sm:text-base">
                  {faq.answer}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
